import { Card, CardContent, Grid, Typography, Box } from "@mui/material";
import { useNavigate } from "react-router-dom";
import createImg from "../images/icon-create.jpg";
import addImg from "../images/add-create.png";

export default function Home() {
  const navigate = useNavigate();

    const cards = [
    { 
      title: "Create New Quiz", 
      path: "/create",
      image: createImg,
      hover: addImg
    },
    { 
      title: "My Quizzes", 
      path: "/my-quizzes",
      image: "/images/myquiz.jpg"
    },
    { 
      title: "Play Quiz", 
      path: "/play",
      image: "/images/play.jpg"
    }
  ];
  return (
    <Grid container spacing={3} padding={5} justifyContent="center">
      {cards.map((item) => (
        <Grid item xs={12} md={4} key={item.title}>
<Card
  onClick={() => navigate(item.path)}
  sx={{
    cursor:"non-clicked",
    height: 240,
    width: 240,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    borderRadius: 3,
    transition: "0.3s",
    position: "relative",
    overflow: "hidden",

    backgroundImage: `
      linear-gradient(rgba(20,9,6,0.2), rgba(20,6,9,0.2)),
      url(${item.image})
    `,
    backgroundSize: "cover",
    backgroundPosition: "center",
    backgroundRepeat: "no-repeat",

    "&::before": {
  content: '""',
  position: "absolute",
  inset: 0,
  backdropFilter: "blur(8px)",
  backgroundColor: "rgba(255,255,255,0.2)", // light overlay
  opacity: 0,
  transition: "0.3s",
  zIndex: 1,
},
"&:hover::before": {
  opacity: 1,
},
    "&:hover": {
      transform: "scale(1.05)",
    },

    "&:hover .card-text": {
      opacity: 0,
    },

    "&:hover .hover-img": {
      opacity: 1,
      transform: "scale(1)",
       cursor: "pointer",
    },
  }}
>

  {/* TEXT */}
  <CardContent sx={{ position: "relative", zIndex: 2 }}>
    <Typography
      variant="h6"
      className="card-text"
      sx={{
        transition: "0.3s",
        fontWeight: "bold",
        color: "black",
      }}
    >
      {item.title}
    </Typography>
  </CardContent>

  {/* HOVER IMAGE */}
  {item.hover && (
    <Box
      component="img"
      src={item.hover}
      className="hover-img"
      sx={{
        position: "absolute",
        width: "20%",
        opacity: 0,
        transition: "0.4s",
        transform: "scale(0.8)",
        zIndex: 3,

        /* REAL SHADOW */
        filter: "drop-shadow(0px 15px 20px rgba(0,0,0,0.6))",
      }}
    />
  )}

</Card>


        </Grid>
      ))}
    </Grid>
  );
}